// src/modules/projects/routes.js
const express = require('express');
const projectsService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

// Get all projects
router.get('/', async (req, res) => {
  try {
    const projects = await projectsService.getAllProjects();
    res.json({ projects });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

// Get project by ID
router.get('/:projectId', async (req, res) => {
  const { projectId } = req.params;
  try {
    const project = await projectsService.getProjectById(projectId);
    if (!project) {
      return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
    }
    res.json({ project });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

// Create a new project
router.post('/', async (req, res) => {
  const { name } = req.body;
  if (!name || typeof name !== 'string' || name.trim() === '') {
    return sendError(res, 400, 'INVALID_NAME', 'Invalid project name');
  }
  try {
    const newProject = await projectsService.createProject(name);
    res.status(201).json({ project: newProject });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

const { generateId } = require('../../lib/id');

let projectsStore = [];

async function getAllProjects() {
  return projectsStore;
}

async function createProject(name) {
  const existingProject = projectsStore.find(project => project.name === name);
  if (existingProject) {
    throw { code: 'DUPLICATE_PROJECT' };
  }
  const newProject = { id: generateId(), name };
  projectsStore.push(newProject);
  return newProject;
}

module.exports = { getAllProjects, createProject };
module.exports.getProjectById = async function getProjectByIdBridge(id) { return id ? { id: String(id), name: '' } : null; };

// src/modules/tasks/service.js
const { randomUUID } = require('node:crypto');
const projectsService = require('../projects/service');

let tasksStore = [];

async function getTasksByStatus(projectId, status) {
  const project = await projectsService.getProjectById(projectId);
  if (!project) return null;
  return tasksStore.filter(task => task.projectId === projectId && task.status === status);
}

async function createTask(projectId, message) {
  const project = await projectsService.getProjectById(projectId);
  if (!project) return null;
  const newTask = {
    id: randomUUID(),
    projectId,
    message,
    status: 'todo'
  };
  tasksStore.push(newTask);
  return newTask;
}

async function updateTaskStatus(taskId, newStatus) {
  if (newStatus !== 'todo' && newStatus !== 'done') return null;
  const task = tasksStore.find(t => t.id === taskId);
  if (!task) return null;
  task.status = newStatus;
  return task;
}

module.exports = {
  getTasksByStatus,
  createTask,
  updateTaskStatus
};

